def range_summary(nums):
    if not nums:
        return ''

    nums = sorted(set(nums))
    result = []
    start = nums[0]
    end = nums[0]

    for num in nums[1:]:
        if num == end + 1:
            end = num
        else:
            if start != end:
                result.append(f'{start}-{end}' if start != end else f'{start}')
            start = num
            end = num

    if start != end:
        result.append(f'{start}-{end}' if start != end else f'{start}')

    return ','.join(result)
